// Config MANUAL (DEV recomendada)

// Instrucciones
// - Debes modificar periodo (period): según periodo que se desea cargar a base de datos (DW)
// - Debes ajustar Selector Filtro Peso (sizeGateEnabled), si es "true" entonces
//   el archivo cargado debe ser mayor a 50 Mb para workflow.

// Config MANUAL (DEV recomendada)
const period = '2024-09';

// Selector de filtro por peso
const sizeGateEnabled = false;       // <-- true = aplica filtro / false = lo ignora
const minFileBytes = 52428800;      // <-- 50 MB (2*1024*1024? no: 50*1024*1024)

// Raíz del data lake dentro del contenedor
const dlRoot = '/data_lake';

// Directorios canónicos (por periodo)
const inboxLic = `${dlRoot}/00_INBOX/LIC/${period}`;
const inboxOC  = `${dlRoot}/00_INBOX/OC/${period}`;

// Nota: el nombre de archivo se arma en el bash:
// LIC_${period}.csv y OC_${period}.csv

return [{
  json: {
    mode: 'MANUAL',
    execMode: 'DEMO_HTTP',
    period,
    dlRoot,
    inboxLic,
    inboxOC,
    sizeGateEnabled,
    minFileBytes,
    _normalized: true,
    _ts: new Date().toISOString(),
  }
}];

// Normalize Context
// Objetivo: entregar un "contexto canónico" al workflow
// - Asegura llaves consistentes (inboxOC vs inboxOc)
// - Asegura tipos (boolean/número/string)
// - Setea defaults seguros para evitar undefined en nodos shell
// - NO toma decisiones del flujo (eso lo hace Check INBOX)

if (!items || items.length !== 1) {
  throw new Error(`[FATAL] Normalize Context: se esperaba 1 item, llegaron ${items?.length ?? 0}`);
}

const src = items[0].json || {};

// Helpers
const asString = (v, def = '') => (v === undefined || v === null ? def : String(v));
const asBool = (v, def = false) => {
  if (v === undefined || v === null || v === '') return def;
  if (typeof v === 'boolean') return v;
  const s = String(v).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'on'].includes(s)) return true;
  if (['false', '0', 'no', 'n', 'off'].includes(s)) return false;
  return def;
};
const asInt = (v, def = 0) => {
  if (v === undefined || v === null || v === '') return def;
  const n = Number(v);
  return Number.isFinite(n) ? Math.trunc(n) : def;
};

// Canonical keys
const mode = asString(src.mode, 'MANUAL');
const execMode = asString(src.execMode, 'DEMO_HTTP');
const period = asString(src.period, '').trim();

const dlRoot = asString(src.dlRoot, '/data_lake');

// OJO: unifica inboxOC (case-sensitive)
const inboxLic = asString(src.inboxLic, period ? `${dlRoot}/00_INBOX/LIC/${period}` : `${dlRoot}/00_INBOX/LIC`);
const inboxOC  = asString(src.inboxOC ?? src.inboxOc, period ? `${dlRoot}/00_INBOX/OC/${period}`  : `${dlRoot}/00_INBOX/OC`);

// Gate por tamaño (solo esto usarás en Check INBOX)
const sizeGateEnabled = asBool(src.sizeGateEnabled, false);
// 50MB default si no viene
const minFileBytes = asInt(src.minFileBytes, 50 * 1024 * 1024);

// Archivos explícitos opcionales (si no, se autoconstruyen en shell)
const licFile = asString(src.licFile, '');
const ocFile  = asString(src.ocFile, '');

// Compose paths opcionales
const composeBase = asString(src.composeBase, '');
const composeN8n  = asString(src.composeN8n, '');

if (!period) {
  // Mantengo esto como error duro porque sin period no hay ejecución determinista
  throw new Error('[FATAL] Normalize Context: falta period (YYYY-MM)');
}

return [
  {
    json: {
      mode,
      execMode,
      period,
      dlRoot,
      inboxLic,
      inboxOC,

      // size gate (único gate operativo)
      sizeGateEnabled,
      minFileBytes,

      // opcionales
      licFile,
      ocFile,
      composeBase,
      composeN8n,

      _normalized: true,
      _ts: new Date().toISOString(),
    },
  },
];

parameters.command:
=/bin/sh -lc '
set -e

MODE="{{ $json.mode }}"
EXECMODE="{{ $json.execMode }}"
PERIOD="{{ $json.period }}"
DLROOT="{{ $json.dlRoot }}"
LIC_DIR="{{ $json.inboxLic }}"
OC_DIR="{{ $json.inboxOC }}"
BASE="{{ $json.composeBase }}"
N8N="{{ $json.composeN8n }}"

echo "[PRE] mode=$MODE" >&2
echo "[PRE] execMode=$EXECMODE" >&2
echo "[PRE] period=$PERIOD" >&2
echo "[PRE] dlRoot(in)=$DLROOT" >&2
echo "[PRE] LIC_DIR(in)=$LIC_DIR" >&2
echo "[PRE] OC_DIR(in)=$OC_DIR" >&2

# --- DEMO_HTTP path (NO docker.sock) ---
if [ "$EXECMODE" = "DEMO_HTTP" ]; then
  echo "[PRE] DEMO_HTTP: skipping docker.sock checks" >&2

  # DLROOT: en DEMO_HTTP NO fallar duro si n8n no ve el DL
  if [ -d "$DLROOT" ]; then
  echo "[OK] Datalake visible en n8n: $DLROOT" >&2
else
  echo "[WARN] Datalake NO visible en n8n: $DLROOT" >&2
fi

  # Health ETL via DNS interno (service name etl)
  node - << "NODE"
const http = require("http");

function fail(code, msg) { console.error(msg); process.exit(code); }

const opts = { host: "etl", port: 8000, path: "/health", timeout: 4000 };

const req = http.get(opts, (res) => {
  let data = "";
  res.on("data", (c) => data += c);
  res.on("end", () => {
    if (res.statusCode !== 200) return fail(21, `[ERROR] ETL /health status=${res.statusCode} body=${data}`);
    try {
      const j = JSON.parse(data);
      if (j.status !== "ok") return fail(22, `[ERROR] ETL /health JSON inesperado: ${data}`);
      console.error("[OK] ETL /health reachable via http://etl:8000/health");
      process.exit(0);
    } catch {
      return fail(23, `[ERROR] ETL /health no es JSON valido: ${data}`);
    }
  });
});
req.on("timeout", () => fail(24, "[ERROR] timeout conectando a ETL /health"));
req.on("error", (e) => fail(25, `[ERROR] fallo conectando a ETL /health: ${e.message}`));
NODE

  echo "[OK] Preflight DEMO_HTTP completo" >&2

  printf "{\"mode\":\"%s\",\"execMode\":\"%s\",\"period\":\"%s\",\"dlRoot\":\"%s\",\"inboxLic\":\"%s\",\"inboxOC\":\"%s\"}\n" \
    "$MODE" "$EXECMODE" "$PERIOD" "$DLROOT" "$LIC_DIR" "$OC_DIR"
  exit 0
fi

# --- LEGACY path (docker.sock required) ---
echo "[PRE] LEGACY: docker.sock checks enabled" >&2
[ -S /var/run/docker.sock ] || { echo "[ERROR] docker.sock no existe" >&2; exit 10; }
command -v docker >/dev/null 2>&1 || { echo "[ERROR] docker CLI no disponible" >&2; exit 11; }
docker version >/dev/null 2>&1 || { echo "[ERROR] docker CLI no conecta al daemon" >&2; exit 12; }

[ -d "$DLROOT" ] || { echo "[ERROR] DataLake mount no existe: $DLROOT" >&2; exit 13; }
[ -f "$BASE" ]  || { echo "[ERROR] No existe compose base: $BASE" >&2; exit 14; }
[ -f "$N8N" ]   || { echo "[ERROR] No existe compose n8n: $N8N" >&2; exit 15; }

echo "[OK] Preflight LEGACY completo" >&2
printf "{\"mode\":\"%s\",\"execMode\":\"%s\",\"period\":\"%s\",\"dlRoot\":\"%s\",\"inboxLic\":\"%s\",\"inboxOC\":\"%s\",\"composeBase\":\"%s\",\"composeN8n\":\"%s\"}\n" \
  "$MODE" "$EXECMODE" "$PERIOD" "$DLROOT" "$LIC_DIR" "$OC_DIR" "$BASE" "$N8N"
'

parameters.jsCode:
// Extract Context (after Preflight)
// Objetivo: tomar el stdout JSON del nodo Preflight y promoverlo a top-level.
// IMPORTANTE: aquí NO existe decision/reason (eso es del INBOX).

if (!items || items.length !== 1) {
  throw new Error(`[FATAL] Extract Context (after Preflight): se esperaba 1 item, llegaron ${items?.length ?? 0}`);
}

const base = items[0].json || {};
const out = base.stdout;

if (typeof out !== 'string' || !out.trim()) {
  throw new Error(`[FATAL] Extract Context (after Preflight): falta stdout JSON del nodo Preflight.`);
}

let pre;
try {
  pre = JSON.parse(out.trim());
} catch (e) {
  throw new Error(
    `[FATAL] Extract Context (after Preflight): stdout no es JSON válido. ` +
    `stdout_head="${String(out).slice(0, 200)}..."`
  );
}

// Campos obligatorios del Preflight (NO decision aquí)
const req = ['mode', 'execMode', 'period', 'dlRoot', 'inboxLic', 'inboxOC'];
for (const k of req) {
  if (pre[k] === undefined || pre[k] === null || String(pre[k]).trim() === '') {
    throw new Error(`[FATAL] Extract Context (after Preflight): falta campo obligatorio ${k} en stdout parseado`);
  }
}

if (!/^\d{4}-\d{2}$/.test(String(pre.period))) {
  throw new Error(`[FATAL] Extract Context (after Preflight): period inválido: ${pre.period}`);
}

return [
  {
    json: {
      ...base,
      ...pre,              // mode/execMode/period/dlRoot/inboxLic/inboxOC
      _pre_exitCode: base.exitCode ?? null,
      _pre_stderr: base.stderr ?? "",
      _normalized: true,
      _ts: new Date().toISOString(),
    },
  },
];

// Extract Context (after INBOX)
// Objetivo: fusionar el contexto base + lo que devuelve el shell (stdout JSON)
// Regla clave: NO debe fallar cuando decision != RUN (MISSING_DIR/MISSING_FILE/QUALITY_GATE).

if (!items || items.length !== 1) {
  throw new Error(`[FATAL] Extract Context (after INBOX): se esperaba 1 item, llegaron ${items?.length ?? 0}`);
}

const base = items[0].json || {};
const out = base.stdout;

if (typeof out !== 'string' || !out.trim()) {
  throw new Error(`[FATAL] Extract Context (after INBOX): falta stdout JSON del nodo shell.`);
}

let inbox;
try {
  inbox = JSON.parse(out.trim());
} catch (e) {
  throw new Error(
    `[FATAL] Extract Context (after INBOX): stdout no es JSON válido. ` +
    `stdout_head="${String(out).slice(0, 200)}..."`
  );
}

// Campos mínimos esperados (pueden estar vacíos dependiendo de decision)
const reqAlways = ['period', 'decision', 'reason', 'reasonText'];
for (const k of reqAlways) {
  if (inbox[k] === undefined || inbox[k] === null || String(inbox[k]).trim() === '') {
    throw new Error(`[FATAL] Extract Context (after INBOX): falta campo obligatorio ${k} en stdout parseado`);
  }
}

// Si decision == RUN, entonces licFile/ocFile deben existir como strings no vacíos
if (String(inbox.decision).toUpperCase() === 'RUN') {
  const reqRun = ['licFile', 'ocFile'];
  for (const k of reqRun) {
    if (inbox[k] === undefined || inbox[k] === null || String(inbox[k]).trim() === '') {
      throw new Error(`[FATAL] Extract Context (after INBOX): decision=RUN pero falta ${k} no vacío`);
    }
  }
}

// Output final: conserva contexto base y sube campos del INBOX a top-level
return [
  {
    json: {
      ...base,     // mantiene mode/execMode/dlRoot/inboxLic/inboxOC/etc.
      ...inbox,    // period/licFile/ocFile/licCols/licBytes/ocBytes/ocLines/decision/reason/reasonText/delim
      _normalized: true,
      _ts: new Date().toISOString(),
    },
  },
];

// Extract Context (after Run) - Code node (JavaScript)
// Objetivo: mantener el contexto base y adjuntar resultado del endpoint /run_period

// 1) Resultado del HTTP (input actual)
const run = items?.[0]?.json ?? {};

// 2) Contexto base: toma el JSON del nodo que ya arma el contexto “bueno” antes del HTTP.
// OJO: AJUSTA el nombre EXACTO del nodo según tu workflow.
const base =
  ($node["Extract Context (after Preflight)"]?.json) ||
  ($node["Extract Context (after INBOX)"]?.json) ||
  ($node["Check INBOX CSV (NO-ERROR)"]?.json) ||
  {};

// 3) Merge final
const merged = {
  ...base,

  // Resultado ETL por HTTP
  etl_ok: run.ok ?? null,
  etl_period: run.period ?? base.period ?? null,
  etl_stdout_tail: run.stdout_tail ?? "",

  // Mantén el payload original del endpoint por trazabilidad
  etl_http_response: run,
};

return [{ json: merged }];

const decision = $json.decision || 'NO_OP';
const reason = $json.reason || 'OK';

return [{
  json: {
    decision,
    reason,
    reasonText: `${decision}: ${reason}`,
  }
}];

// Classify Decision
// Objetivo: clasificar RUN / NO_OP / EXCEPCION_FUENTE y reasonText humano.
// Regla: si faltan campos críticos, FATAL.

const period =
  $json.period ??
  $node["Extract Context (after INBOX)"]?.json?.period ??
  $node["Extract Context (after Preflight)"]?.json?.period ??
  $node["Normalize Context"]?.json?.period ??
  $node["Config MANUAL"]?.json?.period;

if (!period || !/^\d{4}-\d{2}$/.test(period)) {
  throw new Error(`[FATAL] period inválido o ausente: ${period}`);
}

const reasonCode = $json.reason || "UNKNOWN";
let decision = $json.decision || "NO_OP";

// Excepción controlada (si aplica a tu regla real)
if (period === "2025-01" && reasonCode === "LIC_SCHEMA_ANOM") {
  decision = "EXCEPCION_FUENTE";
}

// Forzado manual (si lo usas en pruebas)
if ($json.forceRun === true) {
  decision = "RUN";
}

const decisionGroup = (decision === "RUN") ? "RUN" : "SKIP";

// Mapa humano (ajusta textos si quieres)
const reasonTextMap = {
  OK: "OK: LIC y OC presentes y pasan validaciones mínimas.",
  MISSING_DIR: "No existe directorio INBOX esperado para el periodo (LIC y/o OC).",
  MISSING_FILE: "Falta archivo CSV esperado en INBOX para el periodo (LIC y/o OC).",
  QUALITY_GATE: "Falla Quality Gate mínimo (columnas/tamaño/filas insuficiente). Requiere revisión.",
  LIC_SCHEMA_ANOM: "LIC con anomalía de esquema (excepción controlada).",
  UNKNOWN: "Motivo no especificado."
};

let reasonText = $json.reasonText || reasonTextMap[reasonCode] || `Motivo: ${reasonCode}`;
let finalReasonCode = reasonCode;

if ($json.forceRun === true) {
  finalReasonCode = "FORCED_RUN";
  reasonText = "Prueba controlada: se fuerza RUN para validar bifurcación.";
}

return [{
  json: {
    ...$json,
    period,
    decision,
    decisionGroup,
    reason: finalReasonCode,
    reasonCode: finalReasonCode,
    reasonText,
  }
}];
